				cargoProductRow.Product = item;
				cargoProductRow.ProductName.Text = item.Name;
				((Control)cargoProductRow.MainButton).ToolTip = item.Description;
				cargoProductRow.PointCost.Text = Loc.GetString("cargo-console-menu-points-amount", new(string, object)[1] { ("amount", item.Cost.ToString()) });
