				};
				((Control)Products).AddChild((Control)(object)cargoProductRow2);
			}
		}
	}

	public void PopulateCategories()
	{
		_categoryStrings.Clear();
		Categories.Clear();
		foreach (CargoProductPrototype productPrototype in ProductPrototypes)
		{
			if (!_categoryStrings.Contains(Loc.GetString(productPrototype.Category)))
			{
				_categoryStrings.Add(Loc.GetString(productPrototype.Category));
			}
		}
		_categoryStrings.Sort();
		_categoryStrings.Insert(0, Loc.GetString("cargo-console-menu-populate-categories-all-text"));
		foreach (string categoryString in _categoryStrings)
		{
			Categories.AddItem(categoryString, (int?)null);
		}
	}

